-- ============================================================
-- SÃO RAFAEL - DATABASE SETUP (Full Reset + Migration)
-- Executes all migrations in sequence
-- ============================================================

-- Enable required extensions
CREATE EXTENSION IF NOT EXISTS vector;
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- ============================================
-- 1. BASE TABLES
-- ============================================
CREATE TABLE IF NOT EXISTS saorafael_users (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  email TEXT UNIQUE NOT NULL,
  full_name TEXT,
  role TEXT DEFAULT 'usuario' CHECK (role IN ('admin','usuario','visualizador')),
  confirmed BOOLEAN DEFAULT FALSE,
  company_name TEXT DEFAULT 'saorafael',
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS saorafael_wizard_submission (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT UNIQUE,
  user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  client_id UUID,
  form_data JSONB NOT NULL DEFAULT '{}',
  status TEXT DEFAULT 'submitted' CHECK (status IN ('submitted','processing','completed','error')),
  protocol TEXT,
  submitted_at TIMESTAMPTZ DEFAULT NOW(),
  processed_at TIMESTAMPTZ,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS saorafael_chat_message (
  id BIGSERIAL PRIMARY KEY,
  session_id TEXT NOT NULL,
  user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  message JSONB NOT NULL DEFAULT '{}',
  created_at TIMESTAMPTZ DEFAULT NOW()
);

-- ============================================
-- 2. CLIENTS TABLE
-- ============================================
CREATE TABLE IF NOT EXISTS saorafael_clients (
  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
  razao_social TEXT NOT NULL,
  cnpj_cpf TEXT,
  inscricao_estadual TEXT,
  endereco TEXT,
  cidade TEXT,
  estado TEXT,
  cep TEXT,
  contato_nome TEXT,
  contato_telefone TEXT,
  contato_email TEXT,
  dados_tecnicos TEXT,
  local_instalacao TEXT,
  telefone TEXT,
  email TEXT,
  observacoes TEXT,
  created_by UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  created_at TIMESTAMPTZ DEFAULT NOW(),
  updated_at TIMESTAMPTZ DEFAULT NOW()
);

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'saorafael_clients' AND column_name = 'observacoes') THEN
    ALTER TABLE saorafael_clients ADD COLUMN observacoes TEXT;
  END IF;
END $$;

CREATE INDEX IF NOT EXISTS idx_saorafael_clients_razao_social_trgm ON saorafael_clients USING gin (razao_social gin_trgm_ops);
CREATE INDEX IF NOT EXISTS idx_saorafael_clients_cnpj_cpf ON saorafael_clients (cnpj_cpf);
CREATE INDEX IF NOT EXISTS idx_saorafael_clients_cidade ON saorafael_clients (cidade);

DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'saorafael_wizard_submission' AND column_name = 'client_id') THEN
    ALTER TABLE saorafael_wizard_submission ADD COLUMN client_id UUID;
  END IF;
END $$;

-- ============================================
-- 3. VECTOR STORE: TRUNCATE + RECREATE (RAG Reset)
-- ============================================
CREATE TABLE IF NOT EXISTS saorafael_documents (
  id bigserial PRIMARY KEY,
  content text,
  metadata jsonb,
  embedding vector(1536)
);
TRUNCATE TABLE saorafael_documents;

CREATE OR REPLACE FUNCTION saorafael_match_documents (
  query_embedding vector(1536),
  match_count int DEFAULT NULL,
  filter jsonb DEFAULT '{}'
) RETURNS TABLE (
  id bigint,
  content text,
  metadata jsonb,
  similarity float
)
LANGUAGE plpgsql
AS $$
#variable_conflict use_column
BEGIN
  RETURN QUERY
  SELECT id, content, metadata, 1 - (saorafael_documents.embedding <=> query_embedding) AS similarity
  FROM saorafael_documents
  WHERE metadata @> filter
  ORDER BY saorafael_documents.embedding <=> query_embedding
  LIMIT match_count;
END;
$$;

-- ============================================
-- 4. CHAT HISTORY: TRUNCATE
-- ============================================
TRUNCATE TABLE saorafael_chat_message;

-- ============================================
-- 5. USER CRUD FUNCTIONS (from migration 002)
-- ============================================
CREATE OR REPLACE FUNCTION saorafael_is_admin()
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM auth.users
    WHERE id = auth.uid()
      AND raw_user_meta_data->>'company_name' = 'saorafael'
      AND raw_user_meta_data->>'role' = 'admin'
  );
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_list_users()
RETURNS TABLE (id UUID, email TEXT, created_at TIMESTAMPTZ, last_sign_in_at TIMESTAMPTZ, role TEXT, full_name TEXT, confirmed BOOLEAN)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF NOT saorafael_is_admin() THEN
    RAISE EXCEPTION 'Acesso negado: apenas administradores.';
  END IF;
  RETURN QUERY
  SELECT u.id, u.email::TEXT, u.created_at, u.last_sign_in_at,
    COALESCE(u.raw_user_meta_data->>'role', 'visualizador')::TEXT,
    COALESCE(u.raw_user_meta_data->>'full_name', '')::TEXT,
    (u.email_confirmed_at IS NOT NULL)
  FROM auth.users u
  WHERE u.raw_user_meta_data->>'company_name' = 'saorafael'
  ORDER BY u.created_at DESC;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_confirm_user(target_user_id UUID)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT saorafael_is_admin() THEN RAISE EXCEPTION 'Acesso negado'; END IF;
  UPDATE auth.users SET email_confirmed_at = NOW(), updated_at = NOW()
  WHERE id = target_user_id AND raw_user_meta_data->>'company_name' = 'saorafael';
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_update_user(target_user_id UUID, new_role TEXT DEFAULT NULL, new_full_name TEXT DEFAULT NULL)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE meta JSONB;
BEGIN
  IF NOT saorafael_is_admin() THEN RAISE EXCEPTION 'Acesso negado'; END IF;
  SELECT raw_user_meta_data INTO meta FROM auth.users WHERE id = target_user_id AND raw_user_meta_data->>'company_name' = 'saorafael';
  IF meta IS NULL THEN RAISE EXCEPTION 'Usuário não encontrado'; END IF;
  IF new_role IS NOT NULL THEN meta = jsonb_set(meta, '{role}', to_jsonb(new_role)); END IF;
  IF new_full_name IS NOT NULL THEN meta = jsonb_set(meta, '{full_name}', to_jsonb(new_full_name)); END IF;
  UPDATE auth.users SET raw_user_meta_data = meta, updated_at = NOW() WHERE id = target_user_id;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_delete_user(target_user_id UUID)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  IF NOT saorafael_is_admin() THEN RAISE EXCEPTION 'Acesso negado'; END IF;
  IF target_user_id = auth.uid() THEN RAISE EXCEPTION 'Não pode excluir a si mesmo'; END IF;
  DELETE FROM auth.users WHERE id = target_user_id AND raw_user_meta_data->>'company_name' = 'saorafael';
END;
$$;

-- ============================================
-- 6. CLIENT CRUD FUNCTIONS (from migration 011)
-- ============================================
CREATE OR REPLACE FUNCTION saorafael_search_clients(p_query TEXT)
RETURNS TABLE (id UUID, razao_social TEXT, cnpj_cpf TEXT, telefone TEXT, email TEXT, cidade TEXT, estado TEXT, total_orcamentos BIGINT, ultimo_orcamento TIMESTAMPTZ)
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN QUERY
  SELECT c.id, c.razao_social, c.cnpj_cpf, c.telefone, c.email, c.cidade, c.estado,
    COUNT(s.id)::BIGINT AS total_orcamentos, MAX(s.submitted_at)::TIMESTAMPTZ AS ultimo_orcamento
  FROM saorafael_clients c
  LEFT JOIN saorafael_wizard_submission s ON s.client_id = c.id
  WHERE REPLACE(REPLACE(REPLACE(c.cnpj_cpf, '.', ''), '-', ''), '/', '') ILIKE '%' || REPLACE(REPLACE(REPLACE(p_query, '.', ''), '-', ''), '/', '') || '%'
    OR c.razao_social ILIKE '%' || p_query || '%'
    OR REPLACE(REPLACE(REPLACE(REPLACE(c.telefone, '(', ''), ')', ''), '-', ''), ' ', '') ILIKE '%' || REPLACE(REPLACE(REPLACE(REPLACE(p_query, '(', ''), ')', ''), '-', ''), ' ', '') || '%'
  GROUP BY c.id, c.razao_social, c.cnpj_cpf, c.telefone, c.email, c.cidade, c.estado
  ORDER BY CASE WHEN REPLACE(REPLACE(REPLACE(c.cnpj_cpf, '.', ''), '-', ''), '/', '') = REPLACE(REPLACE(REPLACE(p_query, '.', ''), '-', ''), '/', '') THEN 0 ELSE 1 END, c.razao_social <-> p_query, MAX(s.submitted_at) DESC NULLS LAST
  LIMIT 10;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_client_detail(p_client_id UUID)
RETURNS TABLE (id UUID, razao_social TEXT, cnpj_cpf TEXT, inscricao_estadual TEXT, telefone TEXT, email TEXT, cidade TEXT, estado TEXT, cep TEXT, endereco TEXT, local_instalacao TEXT, contato_nome TEXT, contato_telefone TEXT, contato_email TEXT, dados_tecnicos TEXT, created_at TIMESTAMPTZ)
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN QUERY SELECT c.id, c.razao_social, c.cnpj_cpf, c.inscricao_estadual, c.telefone, c.email, c.cidade, c.estado, c.cep, c.endereco, c.local_instalacao, c.contato_nome, c.contato_telefone, c.contato_email, c.dados_tecnicos, c.created_at FROM saorafael_clients c WHERE c.id = p_client_id;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_upsert_client(
  p_razao_social TEXT, p_cnpj_cpf TEXT DEFAULT NULL, p_telefone TEXT DEFAULT NULL, p_email TEXT DEFAULT NULL,
  p_cidade TEXT DEFAULT NULL, p_estado TEXT DEFAULT NULL, p_cep TEXT DEFAULT NULL, p_endereco TEXT DEFAULT NULL,
  p_local_instalacao TEXT DEFAULT NULL, p_contato_nome TEXT DEFAULT NULL, p_contato_telefone TEXT DEFAULT NULL,
  p_contato_email TEXT DEFAULT NULL, p_inscricao_estadual TEXT DEFAULT NULL
)
RETURNS UUID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_id UUID;
BEGIN
  IF p_cnpj_cpf IS NOT NULL AND TRIM(p_cnpj_cpf) != '' THEN
    SELECT sc.id INTO v_id FROM saorafael_clients sc WHERE sc.cnpj_cpf = TRIM(p_cnpj_cpf);
  END IF;
  IF v_id IS NOT NULL THEN
    UPDATE saorafael_clients SET
      razao_social = COALESCE(NULLIF(TRIM(p_razao_social), ''), razao_social),
      telefone = COALESCE(NULLIF(TRIM(p_telefone), ''), telefone),
      email = COALESCE(NULLIF(TRIM(p_email), ''), email),
      cidade = COALESCE(NULLIF(TRIM(p_cidade), ''), cidade),
      estado = COALESCE(NULLIF(TRIM(p_estado), ''), estado),
      cep = COALESCE(NULLIF(TRIM(p_cep), ''), cep),
      endereco = COALESCE(NULLIF(TRIM(p_endereco), ''), endereco),
      local_instalacao = COALESCE(NULLIF(TRIM(p_local_instalacao), ''), local_instalacao),
      contato_nome = COALESCE(NULLIF(TRIM(p_contato_nome), ''), contato_nome),
      contato_telefone = COALESCE(NULLIF(TRIM(p_contato_telefone), ''), contato_telefone),
      contato_email = COALESCE(NULLIF(TRIM(p_contato_email), ''), contato_email),
      inscricao_estadual = COALESCE(NULLIF(TRIM(p_inscricao_estadual), ''), inscricao_estadual),
      updated_at = NOW()
    WHERE saorafael_clients.id = v_id;
  ELSE
    INSERT INTO saorafael_clients (razao_social, cnpj_cpf, telefone, email, cidade, estado, cep, endereco, local_instalacao, contato_nome, contato_telefone, contato_email, inscricao_estadual, created_by)
    VALUES (TRIM(p_razao_social), NULLIF(TRIM(p_cnpj_cpf),''), NULLIF(TRIM(p_telefone),''), NULLIF(TRIM(p_email),''), NULLIF(TRIM(p_cidade),''), NULLIF(TRIM(p_estado),''), NULLIF(TRIM(p_cep),''), NULLIF(TRIM(p_endereco),''), NULLIF(TRIM(p_local_instalacao),''), NULLIF(TRIM(p_contato_nome),''), NULLIF(TRIM(p_contato_telefone),''), NULLIF(TRIM(p_contato_email),''), NULLIF(TRIM(p_inscricao_estadual),''), auth.uid())
    RETURNING saorafael_clients.id INTO v_id;
  END IF;
  RETURN v_id;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_delete_client(p_client_id UUID)
RETURNS JSONB LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_deleted INT; v_razao TEXT;
BEGIN
  SELECT razao_social INTO v_razao FROM saorafael_clients WHERE id = p_client_id;
  IF v_razao IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'Cliente não encontrado'); END IF;
  DELETE FROM saorafael_wizard_submission WHERE client_id = p_client_id;
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  DELETE FROM saorafael_clients WHERE id = p_client_id;
  RETURN jsonb_build_object('success', true, 'cliente', v_razao, 'orcamentos_removidos', v_deleted);
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_delete_submission_smart(p_submission_id BIGINT)
RETURNS JSONB LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE v_client_id UUID; v_protocol TEXT; v_remaining INT; v_client_deleted BOOLEAN := false; v_razao TEXT;
BEGIN
  SELECT client_id, protocol INTO v_client_id, v_protocol FROM saorafael_wizard_submission WHERE id = p_submission_id;
  IF v_protocol IS NULL THEN RETURN jsonb_build_object('success', false, 'error', 'Orçamento não encontrado'); END IF;
  DELETE FROM saorafael_wizard_submission WHERE id = p_submission_id;
  IF v_client_id IS NOT NULL THEN
    SELECT COUNT(*) INTO v_remaining FROM saorafael_wizard_submission WHERE client_id = v_client_id;
    IF v_remaining = 0 THEN
      SELECT razao_social INTO v_razao FROM saorafael_clients WHERE id = v_client_id;
      DELETE FROM saorafael_clients WHERE id = v_client_id;
      v_client_deleted := true;
    END IF;
  END IF;
  RETURN jsonb_build_object('success', true, 'protocol', v_protocol, 'client_deleted', v_client_deleted, 'client_name', COALESCE(v_razao, null));
END;
$$;

-- ============================================
-- 7. RLS POLICIES
-- ============================================
ALTER TABLE saorafael_wizard_submission ENABLE ROW LEVEL SECURITY;
ALTER TABLE saorafael_chat_message ENABLE ROW LEVEL SECURITY;
ALTER TABLE saorafael_clients ENABLE ROW LEVEL SECURITY;

DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_clients_select_policy ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_insert_policy ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_update_own ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_update_admin ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_clients_delete_policy ON saorafael_clients;
  CREATE POLICY saorafael_clients_select_policy ON saorafael_clients FOR SELECT TO authenticated USING (true);
  CREATE POLICY saorafael_clients_insert_policy ON saorafael_clients FOR INSERT TO authenticated WITH CHECK (created_by = auth.uid());
  CREATE POLICY saorafael_clients_update_own ON saorafael_clients FOR UPDATE TO authenticated USING (created_by = auth.uid() OR saorafael_is_admin());
  CREATE POLICY saorafael_clients_delete_policy ON saorafael_clients FOR DELETE TO authenticated USING (saorafael_is_admin());
END $$;

DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_submission_select_all ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_submission_insert ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_submission_update ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_submission_delete ON saorafael_wizard_submission;
  CREATE POLICY saorafael_submission_select_all ON saorafael_wizard_submission FOR SELECT TO authenticated USING (true);
  CREATE POLICY saorafael_submission_insert ON saorafael_wizard_submission FOR INSERT TO authenticated WITH CHECK (true);
  CREATE POLICY saorafael_submission_update ON saorafael_wizard_submission FOR UPDATE TO authenticated USING (user_id = auth.uid() OR saorafael_is_admin());
  CREATE POLICY saorafael_submission_delete ON saorafael_wizard_submission FOR DELETE TO authenticated USING (saorafael_is_admin());
END $$;

DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_chat_select ON saorafael_chat_message;
  DROP POLICY IF EXISTS saorafael_chat_insert ON saorafael_chat_message;
  DROP POLICY IF EXISTS saorafael_chat_delete ON saorafael_chat_message;
  CREATE POLICY saorafael_chat_select ON saorafael_chat_message FOR SELECT TO authenticated USING (user_id = auth.uid() OR saorafael_is_admin());
  CREATE POLICY saorafael_chat_insert ON saorafael_chat_message FOR INSERT TO authenticated WITH CHECK (true);
  CREATE POLICY saorafael_chat_delete ON saorafael_chat_message FOR DELETE TO authenticated USING (user_id = auth.uid() OR saorafael_is_admin());
END $$;

DO $$ BEGIN
  DROP POLICY IF EXISTS saorafael_clients_service_role ON saorafael_clients;
  DROP POLICY IF EXISTS saorafael_submission_service_role ON saorafael_wizard_submission;
  DROP POLICY IF EXISTS saorafael_chat_service_role ON saorafael_chat_message;
  CREATE POLICY saorafael_clients_service_role ON saorafael_clients FOR ALL TO service_role USING (true) WITH CHECK (true);
  CREATE POLICY saorafael_submission_service_role ON saorafael_wizard_submission FOR ALL TO service_role USING (true) WITH CHECK (true);
  CREATE POLICY saorafael_chat_service_role ON saorafael_chat_message FOR ALL TO service_role USING (true) WITH CHECK (true);
END $$;

-- ============================================
-- 8. SESSION MANAGEMENT FUNCTIONS (migrations 005/010)
-- ============================================
DROP FUNCTION IF EXISTS saorafael_list_sessions();
CREATE FUNCTION saorafael_list_sessions()
RETURNS TABLE (session_id TEXT, titulo TEXT, data_inicio TIMESTAMPTZ, data_ultimo TIMESTAMPTZ, total_mensagens BIGINT)
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN QUERY
  SELECT m.session_id::TEXT,
    LEFT(SPLIT_PART((SELECT m2.message->>'content' FROM saorafael_chat_message m2 WHERE m2.session_id = m.session_id AND m2.message->>'type' = 'human' ORDER BY m2.created_at ASC LIMIT 1), '[CONTEXTO', 1), 80)::TEXT AS titulo,
    MIN(m.created_at)::TIMESTAMPTZ, MAX(m.created_at)::TIMESTAMPTZ, COUNT(*)::BIGINT
  FROM saorafael_chat_message m
  WHERE m.user_id = auth.uid() OR m.user_id IS NULL
  GROUP BY m.session_id
  ORDER BY MAX(m.created_at) DESC;
END;
$$;

DROP FUNCTION IF EXISTS saorafael_get_history(TEXT);
CREATE FUNCTION saorafael_get_history(p_session_id TEXT)
RETURNS TABLE (id BIGINT, message JSONB, created_at TIMESTAMPTZ)
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN QUERY SELECT cm.id::BIGINT, cm.message::JSONB, cm.created_at::TIMESTAMPTZ
  FROM saorafael_chat_message cm WHERE cm.session_id = p_session_id ORDER BY cm.created_at ASC;
END;
$$;

DROP FUNCTION IF EXISTS saorafael_delete_session(TEXT);
CREATE FUNCTION saorafael_delete_session(p_session_id TEXT)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  DELETE FROM saorafael_chat_message WHERE session_id = p_session_id;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_prune_history(p_session_id TEXT, p_keep_last INT DEFAULT 10)
RETURNS INT LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE deleted_count INT;
BEGIN
  WITH to_keep AS (SELECT cm.id FROM saorafael_chat_message cm WHERE cm.session_id = p_session_id ORDER BY cm.created_at DESC LIMIT p_keep_last)
  DELETE FROM saorafael_chat_message WHERE session_id = p_session_id AND id NOT IN (SELECT id FROM to_keep);
  GET DIAGNOSTICS deleted_count = ROW_COUNT;
  RETURN deleted_count;
END;
$$;

CREATE OR REPLACE FUNCTION saorafael_update_own_name(new_full_name TEXT)
RETURNS VOID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE meta JSONB;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Não autenticado.'; END IF;
  SELECT raw_user_meta_data INTO meta FROM auth.users WHERE id = auth.uid() AND raw_user_meta_data->>'company_name' = 'saorafael';
  IF meta IS NULL THEN RAISE EXCEPTION 'Usuário não encontrado.'; END IF;
  meta = jsonb_set(meta, '{full_name}', to_jsonb(new_full_name));
  UPDATE auth.users SET raw_user_meta_data = meta, updated_at = NOW() WHERE id = auth.uid();
END;
$$;

-- ============================================
-- 9. CREATE USER FUNCTION (migration 006)
-- ============================================
CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE OR REPLACE FUNCTION saorafael_create_user(p_email TEXT, p_password TEXT, p_full_name TEXT DEFAULT '', p_role TEXT DEFAULT 'usuario')
RETURNS UUID LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
DECLARE new_user_id UUID;
BEGIN
  IF NOT saorafael_is_admin() THEN RAISE EXCEPTION 'Acesso negado'; END IF;
  IF p_role NOT IN ('admin','usuario','visualizador') THEN RAISE EXCEPTION 'Role inválido'; END IF;
  IF EXISTS (SELECT 1 FROM auth.users WHERE email = p_email) THEN RAISE EXCEPTION 'Usuário com este email já existe.'; END IF;
  INSERT INTO auth.users (instance_id, id, aud, role, email, encrypted_password, email_confirmed_at, raw_user_meta_data, created_at, updated_at)
  VALUES ('00000000-0000-0000-0000-000000000000', gen_random_uuid(), 'authenticated', 'authenticated', p_email, crypt(p_password, gen_salt('bf')), NOW(),
    jsonb_build_object('company_name','saorafael','role',p_role,'full_name',p_full_name), NOW(), NOW())
  RETURNING id INTO new_user_id;
  INSERT INTO auth.identities (id, user_id, identity_data, provider, provider_id, last_sign_in_at, created_at, updated_at)
  VALUES (gen_random_uuid(), new_user_id, jsonb_build_object('sub', new_user_id::text, 'email', p_email), 'email', new_user_id::text, NOW(), NOW(), NOW());
  RETURN new_user_id;
END;
$$;

-- ============================================
-- 10. CLIENT SUBMISSIONS FUNCTION (migration 011)
-- ============================================
CREATE OR REPLACE FUNCTION saorafael_client_submissions(p_client_id UUID)
RETURNS TABLE (id BIGINT, protocol TEXT, status TEXT, tipo_produto TEXT, dimensoes TEXT, submitted_at TIMESTAMPTZ, processed_at TIMESTAMPTZ)
LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$
BEGIN
  RETURN QUERY SELECT s.id::BIGINT, s.protocol::TEXT, s.status::TEXT,
    (s.form_data->'step1'->>'tipo_produto')::TEXT,
    (COALESCE(s.form_data->'step3'->>'comprimento','?')||'x'||COALESCE(s.form_data->'step3'->>'largura','?')||'x'||COALESCE(s.form_data->'step3'->>'altura','?')||'m')::TEXT,
    s.submitted_at::TIMESTAMPTZ, s.processed_at::TIMESTAMPTZ
